import { Lesson } from './types';
import { createLesson } from './data_helpers';

export const efLessonsB1: Lesson[] = [
  createLesson('g2-ef-b1-l1', 'L1: 2ª Série — Revisão e Aprofundamento em EF', 'educacao_fisica', 'A 2ª Série representa um momento de consolidação e aprofundamento. Revisamos os fundamentos estudados na 1ª Série: conceitos de saúde, aptidão física, esportes coletivos e individuais, lutas, dança e ginástica. Neste ano, iremos além: analisaremos criticamente o esporte como fenômeno social, exploraremos práticas corporais avançadas e desenvolveremos autonomia para planejar nossa própria vida ativa. Diagnóstico: avaliação das capacidades físicas atuais (resistência aeróbia, força/resistência muscular, flexibilidade, velocidade) e comparação com as medidas da 1ª Série. Estabelecimento de metas individuais para o ano.', ['Comparando com a 1ª Série, em quais capacidades físicas você nota mais desenvolvimento? Em quais ainda precisa avançar?', 'Quais práticas corporais você manteve fora da escola ao longo do ano? O que isso revela sobre seus interesses e hábitos?']),
  createLesson('g2-ef-b1-l2', 'L2: Esporte como Fenômeno Social e Cultural', 'educacao_fisica', 'O esporte não é apenas atividade física — é um fenômeno social complexo. Pierre Bourdieu analisou o esporte como campo de disputa de poder, onde o "habitus corporal" de cada classe social determina os esportes praticados (polo, golfe e tênis para a elite; futebol e capoeira para as classes populares). O esporte pode reproduzir desigualdades, mas também pode ser espaço de resistência e mobilidade social. Exemplos brasileiros: a trajetória de atletas negros e periféricos no futebol, no atletismo (Thiago Braz), no tênis de mesa (Hugo Calderano). O esporte como espetáculo: a mercantilização do corpo atlético. A Copa do Mundo e os Jogos Olímpicos como eventos geopolíticos.', ['Como Bourdieu explica a relação entre classe social e esporte praticado? Você vê isso na realidade do Tocantins?', 'Dê um exemplo de atleta brasileiro cuja trajetória mostra o esporte como possibilidade de mobilidade social. Quais foram os desafios enfrentados?']),
  createLesson('g2-ef-b1-l3', 'L3: Futebol Aprofundado — Táticas e Análise de Jogo', 'educacao_fisica', 'O futebol é a modalidade esportiva mais popular do Brasil e do mundo, com ~4 bilhões de adeptos. Aprofundamento tático: sistemas táticos modernos (4-3-3, 4-2-3-1, 3-5-2); pressing e contra-pressing; construção de jogo desde o goleiro; transições rápidas. Análise de jogo: como assistir ao futebol com olhar crítico (movimentação sem bola, pressing triggers, análise de espaços). Futebol feminino no Brasil: trajetória de Marta (6 vezes Bola de Ouro da FIFA), discriminação histórica (o futebol feminino foi proibido no Brasil de 1941 a 1979 pelo decreto 3.199), crescimento atual. Prática: aplicação de sistemas táticos em jogo reduzido 5x5.', ['Por que o futebol feminino foi proibido no Brasil por décadas? Que valores sociais estão por trás dessa proibição?', 'Explique a diferença entre os sistemas táticos 4-3-3 e 4-2-3-1. Quais são as vantagens e desvantagens de cada um?']),
  createLesson('g2-ef-b1-l4', 'L4: Voleibol — Sistemas de Jogo e Líbero', 'educacao_fisica', 'O voleibol brasileiro é referência mundial: maior campeão olímpico masculino, e Sheilla Castro, Fabi e Jaqueline são ícones femininos. Aprofundamento técnico: fundamentos avançados (float serve, jump serve, pipe attack); o sistema W e o sistema 4-2 vs. 5-1. A função do líbero: criado em 1996, o líbero é o especialista em defesa que usa colete diferente, não pode atacar e entra livremente. Regras especiais do líbero. Posicionamento em quadra: rotação, cobertura de ataque, formação de defesa. Prática: jogo com ênfase em diferentes sistemas de levantamento. A psicologia do voleibol: como o esporte exige concentração e comunicação constante.', ['Qual é a função do líbero no voleibol e por que essa posição foi criada? Como ela mudou o jogo?', 'Explique como funciona a rotação de posições no voleibol e por que ela é uma regra fundamental deste esporte.']),
  createLesson('g2-ef-b1-l5', 'L5: Basquetebol — Fast Break e Tática Avançada', 'educacao_fisica', 'O basquetebol é um dos esportes mais táticos do mundo. Aprofundamento: o fast break (contra-ataque em velocidade); o pick-and-roll (bloqueio e finta combinados); zone defense vs. man-to-man defense; o three-pointer e sua revolução no jogo moderno (Stephen Curry e os Golden State Warriors). NBA como liga mais inovadora do mundo — uso de analytics (SportVU, tracking de dados) para otimizar o jogo. Basquete brasileiro: NBB, Oscar Schmidt (maior pontuador de todos os tempos em Mundiais de basquete), Leandro Barbosa no campeonato americano. Basquete de rua (3x3 olímpico desde 2021). Prática: aplicação de pick-and-roll em situação de jogo.', ['O que é o pick-and-roll e por que é considerado uma das jogadas mais eficientes no basquete moderno?', 'Como a análise de dados (analytics) mudou a forma de se jogar e de se treinadores tomarem decisões no basquetebol?']),
  createLesson('g2-ef-b1-l6', 'L6: Handebol — Posições e Sistema Defensivo', 'educacao_fisica', 'O handebol combina velocidade, força e inteligência tática. Aprofundamento: posições específicas (pivô, armador central, armador lateral, ponta); o sistema defensivo 6-0 (todos na área), 5-1 (um adiante), 3-2-1 (agressivo); o goleiro e sua importância (salva ~30% dos arremessos); lances de sete metros. Brasil no handebol: o masculino ainda luta para se estabelecer internacionalmente; o feminino tem crescido. Handebol de areia: modalidade diferente com regras próprias (malabarismo, piruleta). Prática: simulação de sistemas defensivos em jogo. A relação entre handebol e atletismo: por que atletas de atletismo frequentemente se convertem em jogadores de handebol.', ['Qual a diferença entre os sistemas defensivos 6-0 e 5-1 no handebol? Em que situações cada um é mais adequado?', 'Como a função do goleiro no handebol difere do goleiro no futebol? Quais habilidades específicas ele precisa desenvolver?']),
  createLesson('g2-ef-b1-l7', 'L7: Atletismo — Saltos e Arremessos', 'educacao_fisica', 'O atletismo é a "mãe dos esportes" — base de quase todas as modalidades. Aprofundamento em saltos: salto em distância (corrida de aproximação, chamada, fase de voo, aterrissagem); salto triplo (hop, step, jump); salto em altura (técnica Fosbury Flop — criada em 1968 pelos Jogos do México). Arremessos: arremesso de peso (técnica deslizante vs. rotacional), lançamento de disco, lançamento de dardo, arremesso de martelo. Biomecânica dos lançamentos: ângulo ideal de lançamento (~45°), importância da velocidade de saída. Atletas brasileiros: Thiago Braz (salto com vara, ouro olímpico 2016), Alison dos Santos (400 m com barreiras), Adriana Aparecida (maratona). Prática: iniciação ao salto em distância com medição de desempenho.', ['O que é a técnica Fosbury Flop no salto em altura e por que ela revolucionou a modalidade a partir de 1968?', 'Explique a biomecânica básica de um arremesso eficiente: qual é o papel do ângulo de lançamento e da velocidade de saída?']),
  createLesson('g2-ef-b1-l8', 'L8: Esportes de Raquete — Tênis e Tênis de Mesa', 'educacao_fisica', 'Os esportes de raquete desenvolvem coordenação, reflexo, agilidade e estratégia. Tênis: Grand Slams (Wimbledon, Roland Garros, US Open, Australian Open); diferença das superfícies (saibro, grama, piso duro) e como afeta o jogo; fundamentos básicos (forehand, backhand, saque, voleio). Brasil no tênis: Gustavo Kuerten ("Guga") — 3 vezes campeão de Roland Garros, transformou o tênis no Brasil. Tênis de mesa: o esporte mais rápido do mundo (bola a 112 km/h); China dominante há décadas; Hugo Calderano, melhor brasileiro da história (top 10 mundial). Badminton: também olímpico, muito popular na Ásia. Prática: iniciação ao tênis de mesa com ênfase em coordenação e reflexo.', ['Por que as diferentes superfícies de jogo (saibro, grama, piso duro) influenciam tanto o estilo de jogo dos tenistas?', 'Como o desempenho de Gustavo Kuerten em Roland Garros impactou o desenvolvimento do tênis no Brasil?']),
  createLesson('g2-ef-b1-l9', 'L9: Natação — Técnica e Segurança', 'educacao_fisica', 'Natação é habilidade de vida e esporte olímpico. Histórico: incluída nos primeiros Jogos Olímpicos modernos (Atenas, 1896). Quatro estilos: crawl (mais rápido — pernada alternada, braçada alternada); costas (único iniciado na água); peito (mais lento, braçada simétrica); borboleta (mais exigente fisicamente). Técnica básica: respiração rítmica, rolamento corporal no crawl, coordenação braço-perna. Michael Phelps: maior atleta olímpico de todos os tempos (23 ouros em 4 Olimpíadas). Brasil: Daiane Maia, Cesar Cielo (recordista mundial nos 50 m livre, 2009). IMPORTANTE para o Tocantins: segurança em rios e represas — o Rio Araguaia e represas como a da UHE Lajeado têm áreas perigosas. Nunca nadar sozinho.', ['Quais são as diferenças técnicas fundamentais entre os estilos crawl e borboleta na natação?', 'Por que é especialmente importante aprender sobre segurança aquática no Tocantins, considerando os rios e represas da região?']),
  createLesson('g2-ef-b1-l10', 'L10: Lutas — Judô: Filosofia e Técnica', 'educacao_fisica', 'O judô foi criado pelo japonês Jigoro Kano em 1882 como método de educação física e moral — "máximo de eficiência com mínimo de esforço" (Seiryoku Zenyo) e "prosperidade e benefício mútuo" (Jita Kyoei). Fundamentos técnicos: ukemi (quedas seguras), ne-waza (técnicas no solo), nage-waza (projeções); graduação por cores de faixa. Judô nas escolas: desenvolve disciplina, respeito, concentração, autocontrole. Brasil é a maior potência do judô fora do Japão: Aurélio Miguel (primeiro ouro olímpico do Brasil, Seul 1988), Rafaela Silva (Rio 2016), David Moura. Judô e inclusão: programa de judô nas favelas do Rio. Prática: ukemi (quedas), posição de guarda, movimentação básica.', ['Quais são os dois princípios filosóficos do judô criados por Jigoro Kano? Como eles se aplicam dentro e fora do tatami?', 'Por que o aprendizado de ukemi (técnicas de queda) é a base fundamental do judô? Qual a importância para a segurança do praticante?']),
  createLesson('g2-ef-b1-l11', 'L11: Ginástica Artística — Aparelhos e Notas', 'educacao_fisica', 'A ginástica artística é um dos esportes mais complexos e exigentes do mundo. Aparelhos masculinos (6): solo, cavalo com alças, argolas, salto, barras paralelas, barra fixa. Aparelhos femininos (4): salto, barras assimétricas, trave, solo. Sistema de pontuação: nota D (dificuldade) + nota E (execução) — juízes decontam erros de execução da nota E. Código de Pontos: atualizado a cada ciclo olímpico. Brasil na ginástica: Rebeca Andrade é a maior ginasta da história do Brasil — 2 ouros olímpicos (Paris 2024), 4 medalhas olímpicas totais, ídolo nacional. Simone Biles (EUA): a GOAT da ginástica, retorno em Paris 2024 após batalha com saúde mental. Prática: solo — sequência básica de acrobacia no colchão.', ['Como funciona o sistema de pontuação atual da ginástica artística (nota D + nota E)? Qual a importância de cada componente?', 'Por que a trajetória de Rebeca Andrade é inspiradora não apenas pelo desempenho esportivo, mas também pelo contexto social de onde ela veio?']),
  createLesson('g2-ef-b1-l12', 'L12: Corpo e Saúde Mental — Conexão Mente-Corpo', 'educacao_fisica', 'A relação entre atividade física e saúde mental é estabelecida pela neurociência: exercício libera serotonina, dopamina e endorfinas — os neurotransmissores do bem-estar. Efeitos comprovados da AF regular na saúde mental: redução de 35% nos sintomas de depressão (tão eficaz quanto antidepressivos em casos moderados), redução de 48% da ansiedade, melhora do sono, aumento da autoestima e autoeficácia. A pandemia de COVID-19 (2020-2022) revelou o impacto devastador do sedentarismo forçado na saúde mental dos jovens. Burnout esportivo: o outro lado — pressão excessiva pode prejudicar a saúde mental de atletas (caso de Simone Biles em Tóquio 2021). Equilíbrio é a palavra-chave.', ['Como a neurociência explica a melhora do estado mental após a prática de exercícios físicos?', 'Qual é o "burnout esportivo" e por que o caso de Simone Biles em Tóquio 2021 foi um marco importante para discutir saúde mental no esporte de alto rendimento?']),
  createLesson('g2-ef-b1-l13', 'L13: Esportes Adaptados e Paralimpismo', 'educacao_fisica', 'O Movimento Paralímpico foi fundado pelo neurologista Ludwig Guttmann em 1948 na Inglaterra, usando o esporte como reabilitação para soldados paraplégicos. Jogos Paralímpicos: paralelos aos Olímpicos desde Roma 1960. Brasil é potência mundial no paralimpismo: 4ª maior delegação em Paris 2024. Modalidades paralímpicas: atletismo adaptado, natação adaptada, goalball (cegos), bocce, basquete em cadeira de rodas, tênis em cadeira, vôlei sentado, futebol de cegos, esgrima adaptada. Classificação funcional: cada atleta é classificado por sua deficiência para competir com igualdade. Daniel Dias (natação), Clodoaldo Silva, Terezinha Guilhermina: ícones do Brasil. A filosofia paralímpica: capacidade, não deficiência.', ['Por que o esporte paralímpico é importante não apenas para atletas com deficiência, mas para toda a sociedade?', 'O que é a classificação funcional no esporte paralímpico e por que ela é necessária para garantir a equidade na competição?']),
  createLesson('g2-ef-b1-l14', 'L14: Nutrição Esportiva — Macronutrientes e Performance', 'educacao_fisica', 'Alimentação é o combustível do corpo para a atividade física. Macronutrientes: Carboidratos (55-60% da dieta de atletas — principal fonte de energia para exercício intenso; fontes: arroz, macarrão, batata, frutas); Proteínas (1,2-2g/kg/dia para atletas — construção e recuperação muscular; fontes: frango, ovo, feijão, leite); Gorduras (20-35% da dieta — energia em repouso e vitaminas lipossolúveis; fontes: azeite, abacate, castanhas). Hidratação: perda de 2% do peso corporal em água reduz desempenho em 20%; necessidade de reposição durante e após o exercício. Refeição pré-treino (2-3h antes): rica em carboidratos, moderada em proteína, baixa em gordura. Refeição pós-treino (até 2h): proteína + carboidrato para recuperação.', ['Por que os carboidratos são considerados o macronutriente mais importante para a performance esportiva de alta intensidade?', 'Crie um plano alimentar de um dia para um atleta que treina à tarde, com refeições pré e pós-treino adequadas.']),
  createLesson('g2-ef-b1-l15', 'L15: Dança de Salão e Ritmos Brasileiros', 'educacao_fisica', 'A dança de salão brasileira incorporou ritmos afro-brasileiros e ibéricos em formas únicas. Forró: ritmo do Nordeste, levado para todo o Brasil; fundamentos básicos (passo básico, giro, balanço). Samba: ritmo nacional por excelência; samba no pé vs. samba de gafieira (dança a dois). Zouk: dança lenta e fluida, criada na Lambada. Axé e pagode: ritmos da Bahia e Rio de Janeiro que chegaram ao Tocantins. A dança de salão como prática social: espaços de encontro, namoro, cultura popular. Comparação com danças internacionais: valsa (Europa), tango (Argentina), salsa (Cuba). Prática: aprender o passo básico do forró — o ritmo mais presente nas festas do interior do Tocantins.', ['Como o forró se tornou símbolo de identidade nordestina e como ele chegou e se transformou no Tocantins?', 'Quais são as principais características que diferenciam o samba no pé do samba de gafieira?']),
  createLesson('g2-ef-b1-l16', 'L16: Avaliação Física — Composição Corporal', 'educacao_fisica', 'A composição corporal é a proporção de massa magra (músculo, osso, água) e massa gorda no organismo. IMC (Índice de Massa Corporal): peso/altura² — útil como triagem, mas impreciso (não diferencia músculo de gordura). Métodos mais precisos: bioimpedância elétrica, dobras cutâneas, DEXA (padrão ouro). Para adolescentes (10-19 anos): valores de referência diferentes dos adultos; puberdade altera a composição corporal. Percentual de gordura saudável para adolescentes: ♂ 11-22%, ♀ 16-27%. Importante: não usar a composição corporal para criar pressão ou vergonha — o objetivo é saúde, não estética. Discussão crítica: como a mídia distorce a imagem corporal e quais os danos psicológicos dessa distorção.', ['Por que o IMC é considerado um método limitado de avaliação da composição corporal? Quais são suas principais limitações?', 'Como a mídia e as redes sociais influenciam a percepção que os jovens têm de seus próprios corpos? Quais são os riscos psicológicos dessa influência?']),
  createLesson('g2-ef-b1-l17', 'L17: Esportes de Aventura — Tocantins e Cerrado', 'educacao_fisica', 'O Tocantins é um estado privilegiado para esportes de aventura. Principais destinos: Jalapão (dunas do Fervedouro, Cachoeira da Fumaça, off-road); Taquaruçu (trilhas, escalada, rapel); Ilha do Bananal (canoagem, pesca esportiva, observação de fauna); Cachoeiras do Tocantins. Modalidades praticadas: trilha e caminhada (trekking), mountain bike, escalada (Morro do Careca, em Taquaruçu), tirolesa, rapel, canoagem, stand-up paddle no Tocantins e Araguaia, arvorismo. Aspectos de segurança: equipamentos adequados (capacete, colete, corda, mosquetão), avaliação de riscos, guia experiente. Sustentabilidade: Leave No Trace (não deixe rastros) — princípios de uso responsável dos ambientes naturais.', ['Por que o Tocantins possui potencial destacado para o turismo de aventura? Quais são os principais atrativos naturais e os esportes praticados em cada um?', 'Quais são os princípios do "Leave No Trace" e por que eles são fundamentais para a preservação dos ambientes naturais onde se praticam esportes de aventura?']),
  createLesson('g2-ef-b1-l18', 'L18: Síntese do 1º Bimestre e Avaliação', 'educacao_fisica', 'Revisão dos principais temas do 1º bimestre: esporte como fenômeno social, aprofundamento técnico de esportes coletivos e individuais, lutas, ginástica, saúde mental e nutrição. Avaliação formativa: questionário conceitual + avaliação prática de uma modalidade à escolha (fundamento técnico específico). Autoavaliação: em quais práticas corporais houve mais engajamento? Por quê? Reflexão: qual a diferença entre praticar uma modalidade por obrigação e praticá-la com sentido? Como encontrar práticas que realmente fazem sentido para sua vida? Meta para o 2º bimestre: cada aluno define uma habilidade técnica ou conhecimento teórico que quer desenvolver.', ['Quais foram os conteúdos do 1º bimestre que mais te interessaram? Por quê?', 'Estabeleça uma meta de desenvolvimento (técnico ou teórico) para o próximo bimestre. Como você vai trabalhar para atingir essa meta?']),
];

export const efLessonsB2: Lesson[] = [
  createLesson('g2-ef-b2-l1', 'L1: Esporte e Direitos Humanos — História e Política', 'educacao_fisica', 'O esporte tem sido palco de importantes manifestações políticas e sociais ao longo da história. Casos históricos: Black Power nos Jogos de 1968 (Tommie Smith e John Carlos erguem o punho negro no pódio, causando expulsão da equipe); boicote de 1980 (EUA) e 1984 (URSS) nas Olimpíadas; Nelson Mandela e o rugby sul-africano (Springboks como símbolo de reconciliação racial no filme "Invictus"). Casos contemporâneos: Colin Kaepernick ajoelhado contra o racismo (NFL, 2016); atletas ucranianos nos jogos sob guerra (2022-2024). No Brasil: protesto dos atletas negros, homenagens a personalidades do movimento negro em pódios olímpicos. O esporte tem obrigação de ser apolítico? Debate.', ['Por que o gesto de Tommie Smith e John Carlos nas Olimpíadas de 1968 foi tão impactante? Quais foram as consequências para eles?', 'O esporte deve ser "apolítico"? Argumente a favor ou contra essa posição usando exemplos históricos.']),
  createLesson('g2-ef-b2-l2', 'L2: Handebol de Areia e Beach Sports', 'educacao_fisica', 'O beach sports é uma tendência global — adaptações de esportes tradicionais para a areia. Beach volleyball: a estrela; Sherif e Lucena (ouro olímpico masculino, Paris 2024); Ana Patrícia e Duda (ouro olímpico feminino, Paris 2024) — o Brasil é bicampeão olímpico. Beach handball: mais acrobático, com "penalidade espetacular" (piruleta com gol vale duplo); mistura de handbal, ginástica e espetáculo. Beach soccer: futebol de areia com times de 5. Beach tennis: combina tênis e vôlei de praia. Adaptações para areia: equilíbrio diferente, maior exigência muscular (especialmente membros inferiores), menor impacto articular. Tocantins: praias de rios — Rio Tocantins (temporada de praias entre julho-outubro).', ['Por que o vôlei de praia brasileiro é tão dominante no cenário mundial? Quais fatores históricos, climáticos e culturais explicam esse sucesso?', 'Quais são as principais diferenças entre o handebol de areia e o handebol de quadra? Como essas diferenças afetam as estratégias de jogo?']),
  createLesson('g2-ef-b2-l3', 'L3: Capoeira Avançada — Angola e Regional', 'educacao_fisica', 'A capoeira é patrimônio imaterial da UNESCO desde 2014. Existe uma divisão histórica importante: Capoeira Angola (Mestre Pastinha, Salvador, BA) — tradicional, mais lúdica, próxima ao chão, valoriza a ancestralidade africana; Capoeira Regional (Mestre Bimba, Salvador, BA) — criada na década de 1930, mais acrobática, introduziu chutes altos e sequências codificadas. Jogo de Angola: mandinga (malandragem, enganação), ginga lenta, baixinha, cabeçada. Jogo Regional: galopes, armadas, meia-lua de compasso, parafuso. O berimbau e seus toques: São Bento Grande (ritmo rápido, Regional), São Bento Pequeno e Idalina (Angola). Prática: ginga, au (roda), bananeira (parada de mão), galpão básico.', ['Quais são as principais diferenças filosóficas e técnicas entre a Capoeira Angola e a Capoeira Regional?', 'Por que a capoeira foi reconhecida pela UNESCO como patrimônio cultural imaterial da humanidade? Qual seu significado para a identidade afro-brasileira?']),
  createLesson('g2-ef-b2-l4', 'L4: Ginástica Rítmica — Arte e Esporte', 'educacao_fisica', 'A ginástica rítmica é exclusivamente feminina nos Jogos Olímpicos (desde Los Angeles 1984) e combina ginástica, ballet, dança e malabarismo. Aparelhos: corda, arco, bola, maças (2), fita. A expressividade é fundamental: sincronia entre o movimento do corpo, o aparelho e a música. Equipe e individual: competições em ambas as categorias. Brasil: a ginástica rítmica tem crescido graças ao investimento e ao sucesso nos Pan-americanos. Kabaeva (Rússia) e os domínios russos e da Europa do Leste. Ginástica rítmica e dança: a fronteira entre esporte e arte — onde um termina e o outro começa? Práticas corporais expressivas: por que movimentos expressivos têm igual valor ao desempenho técnico? Prática: exercícios com arco e bola para desenvolver coordenação e expressividade.', ['Por que a ginástica rítmica é considerada simultaneamente um esporte e uma forma de arte? Quais são as dimensões que fazem dela única?', 'Por que a ginástica rítmica é olímpica apenas para mulheres? Isso deve mudar? Justifique sua posição.']),
  createLesson('g2-ef-b2-l5', 'L5: Prevenção de Lesões — Protocolos e Primeiros Socorros', 'educacao_fisica', 'A prevenção de lesões é mais eficiente que o tratamento. Aquecimento adequado: 5-10 minutos de exercício aeróbio leve + aquecimento dinâmico específico (não estático antes do exercício!). Principais lesões no esporte adolescente: entorse de tornozelo, tendinite patelar (joelho do saltador), síndrome da tíbia medial (canelite), distensão muscular. Protocolo PRICE para lesões agudas: P — Protection (proteção), R — Rest (repouso), I — Ice (gelo: 20 min, 4-6x/dia), C — Compression (compressão com bandagem), E — Elevation (elevação do membro). Quando procurar médico: suspeita de fratura, lesão neurológica, dor intensa que não melhora. Primeiros socorros em desmaio (posição de recuperação) e cãibra (hidratação + alongamento passivo).', ['Qual é o protocolo PRICE e quando deve ser aplicado? Explique cada etapa.', 'Por que o aquecimento dinâmico é preferível ao estático antes de atividades físicas intensas? Quais são os riscos do alongamento estático pré-exercício?']),
  createLesson('g2-ef-b2-l6', 'L6: Yoga e Práticas Integrativas', 'educacao_fisica', 'O yoga tem mais de 5.000 anos de história na Índia e hoje é praticado por 300 milhões de pessoas no mundo. Tipos de yoga: Hatha (mais popular no Brasil — poses estáticas), Vinyasa (fluxo entre poses), Ashtanga (sequências fixas e intensas), Yin (poses longas e restaurativas), Kundalini (foco na energia). Benefícios comprovados: melhora da flexibilidade, força funcional, equilíbrio, concentração e controle do estresse. Asanas básicos: surya namaskar (saudação ao sol — sequência de 12 poses), balasana (pose da criança), savasana (pose do cadáver — relaxamento). Pranayama: técnicas de respiração (respiração alternada, ujjayi, kapalbhati). Meditação mindfulness: prática de atenção plena com base em evidências (Jon Kabat-Zinn, 1979). Prática: mini-sessão de yoga de 20 minutos.', ['Quais são os benefícios físicos e mentais do yoga comprovados pela ciência? Por que o yoga é cada vez mais adotado por atletas de alto rendimento?', 'Descreva a sequência Surya Namaskar (saudação ao sol). Quais grupos musculares cada pose trabalha?']),
  createLesson('g2-ef-b2-l7', 'L7: Esporte e Mídia — Como a TV e as Redes Sociais Transformaram o Esporte', 'educacao_fisica', 'A televisão transformou o esporte em espetáculo global: os primeiros Jogos Olímpicos televisionados ao vivo foram em Roma (1960); hoje, Paris 2024 foi assistido por 3,4 bilhões de pessoas. Efeitos da televisão: mercantilização (direitos de transmissão bilionários), criação de estrelas globais (Michael Jordan, Ronaldo, Serena Williams), horários de jogos mudados para atender às grades de programação. Redes sociais: atletas como influenciadores (Neymar, Cristiano Ronaldo — os mais seguidos do IG), transmissões ao vivo no Instagram, TikTok de atletas. Desvantagens: exposição excessiva, hate online, ansiedade de performance, saúde mental comprometida. Fake news no esporte: desinformação sobre dopping, resultados, transferências. Análise crítica de um episódio de fake news no esporte.', ['Como a televisão transformou o esporte a partir da década de 1960? Quais foram os impactos positivos e negativos?', 'Como as redes sociais mudaram a relação entre atletas e fãs? Quais são os riscos para a saúde mental dos atletas?']),
  createLesson('g2-ef-b2-l8', 'L8: Futebol Americano e Rugby — Contato e Estratégia', 'educacao_fisica', 'Modalidades de contato com alto componente tático. Futebol americano (NFL): o esporte mais popular dos EUA; Super Bowl assistido por 120 milhões de americanos; posições (quarterback, running back, wide receiver, linebacker, cornerback); touchdown, field goal, down and distance. Problemas no futebol americano: CTE (Encefalopatia Traumática Crônica) — doença cerebral causada por pancadas repetidas; o filme "Concussão" (2015) com Will Smith. Rugby: União (15 jogadores, não vale segurar) vs. Liga (13 jogadores, pode passar para trás); tackle, scrum, line-out; os Springboks (África do Sul) e All Blacks (Nova Zelândia); rugby 7 olímpico (desde 2016). Tópico de saúde: como mitigar os riscos de lesões no esporte de contato?', ['Quais são os principais riscos de saúde associados ao futebol americano e ao rugby? Como as federações têm tentado reduzir esses riscos?', 'Explique a diferença entre rugby Union e rugby League. Quais são os aspectos táticos mais importantes de cada modalidade?']),
  createLesson('g2-ef-b2-l9', 'L9: Boxe e Artes Marciais Mistas — Ética e Técnica', 'educacao_fisica', 'Boxe: esporte olímpico desde 1904; desenvolveu a resistência, coordenação, timing e raciocínio tático; Muhammad Ali, o maior de todos os tempos — "flutua como uma borboleta, pica como uma abelha"; boxe feminino olímpico desde 2012 (Bia Ferreira, brasileiro). Técnicas básicas: guarda, jab, direto, gancho, upper cut, esquiva. MMA (Artes Marciais Mistas): combina boxe, wrestling, jiu-jitsu, muay thai, judô; UFC a maior organização mundial; Anderson Silva, José Aldo, Amanda Nunes — campeões mundiais brasileiros. Questão ética: o MMA deveria ser praticado por adolescentes? Questão de saúde pública: regulamentação e proteção dos atletas. Capoeira e MMA: encontros e diálogos.', ['Quais habilidades físicas e mentais o boxe desenvolve além da capacidade de lutar?', 'Há questões éticas no ensino de esportes de contato pleno (como boxe e MMA) para adolescentes? Argumente.']),
  createLesson('g2-ef-b2-l10', 'L10: Esportes Olímpicos de Verão — Contexto Histórico e Cultural', 'educacao_fisica', 'Os Jogos Olímpicos modernos foram criados por Pierre de Coubertin em 1896 em Atenas. Ideal olímpico: paz, fraternidade, excelência. Realidade complexa: exclusão de mulheres até 1900, atletas amadores vs. profissionais, boicotes políticos, doping, corrupção (escândalo da IAAF). Paris 2024: primeira vez com igualdade de gênero completa (50% atletas femininas); cerimônia de abertura revolucionária no Sena. Brasil nos Jogos de Paris 2024: 20 medalhas (7 ouros), 4ª posição — maior resultado histórico. Atletas brasileiros de destaque em Paris: Rebeca Andrade (3 medalhas), Beatriz Souza (judô, ouro), equipe de vôlei feminino. A Olimpíada como evento geopolítico: como os países usam os Jogos para projeção de poder.', ['Por que os Jogos Olímpicos são considerados um evento político além de esportivo? Dê exemplos históricos.', 'Como foi o desempenho do Brasil nos Jogos de Paris 2024? Quais foram os principais destaques e o que esse resultado revela sobre o desenvolvimento do esporte brasileiro?']),
  createLesson('g2-ef-b2-l11', 'L11: Planejamento de Atividade Física — Princípios do Treinamento', 'educacao_fisica', 'Princípios científicos do treinamento esportivo: (1) Princípio da Sobrecarga — o corpo só melhora quando submetido a estímulo maior que o habitual; (2) Princípio da Especificidade — o treino deve ser específico para o objetivo (força, velocidade, resistência); (3) Princípio da Progressão — aumentar a carga gradualmente (10% por semana é a regra geral); (4) Princípio da Individualidade — cada pessoa responde diferente ao mesmo treino (genética, histórico); (5) Princípio da Reversibilidade — sem treino, o condicionamento se perde (~2 semanas para declínio inicial). FITT: Frequência (quantas vezes/semana), Intensidade (% da frequência cardíaca máxima), Tempo (duração), Tipo (aeróbio, força, flexibilidade). Prática: montar um programa de 4 semanas para um objetivo específico.', ['Quais são os 5 princípios do treinamento esportivo? Dê um exemplo prático de como cada um se aplica no treino de um corredor iniciante.', 'Use a fórmula FITT para criar um programa de 4 semanas de corrida para alguém que quer melhorar a resistência cardiovascular.']),
  createLesson('g2-ef-b2-l12', 'L12: Jogos Indígenas — Perspectivas de Tocantins', 'educacao_fisica', 'Os povos indígenas brasileiros têm ricas tradições de práticas corporais: corridas, jogos de arco e flecha, nado em rios, danças rituais, lutas. Jogos Mundiais dos Povos Indígenas: criados em 1996 em Goiânia, ocorrem a cada 2 anos e reúnem etnias do Brasil e do mundo. Destaque do Tocantins: povo Krahô (Mehin) — a corrida de toras é sua prática mais emblemática; toras de buriti carregadas em revezamento por equipes de até 20 pessoas; significado ritual (cura, fertilidade, passagem). Povo Karajá: lutas, corridas, natação no Araguaia. Povo Xerente: arco e flecha, corrida. A FUNAI e os Jogos dos Povos Indígenas apoiam a preservação dessas práticas. Propósito pedagógico: valorizar a diversidade corporal e cultural.', ['Por que é importante incluir práticas corporais indígenas nas aulas de Educação Física? O que elas nos ensinam sobre a diversidade humana?', 'Descreva a corrida de toras do povo Krahô: como funciona, qual seu significado cultural e o que ela exige fisicamente dos participantes?']),
  createLesson('g2-ef-b2-l13', 'L13: Natação Avançada e Esportes Aquáticos', 'educacao_fisica', 'Aprofundamento em natação e modalidades aquáticas. Apneia estática: como apneístas treinam para a glote; recordes mundiais de apneia (mais de 20 minutos). Polo aquático: combinação de natação, handebol e rugby dentro da água; regras básicas. Maratona aquática: prova de 10 km em águas abertas (olímpica desde 2008). Nado sincronizado (Natação Artística): fusão de natação, ginástica e dança; exigência extrema de resistência subaquática e coordenação. Hidroginástica: adaptação da ginástica aeróbica para a água; indicada para todas as idades, menor impacto. Caiaque e canoagem olímpica: tipos de embarcações (K1, C1, K2, C2); canoagem de velocidade vs. canoagem de águas brancas (slalom). No Tocantins: canoagem no Rio Araguaia e no Rio Tocantins — prática popular e esporte.', ['Quais são as principais diferenças entre a natação competitiva e a natação artística (sincronizada) em termos de habilidades exigidas?', 'Por que a canoagem é especialmente relevante para o Tocantins? Quais são as oportunidades e os cuidados necessários para sua prática nos rios locais?']),
  createLesson('g2-ef-b2-l14', 'L14: Xadrez e Esportes da Mente', 'educacao_fisica', 'Xadrez foi reconhecido pelo Comitê Olímpico Internacional como esporte, embora não seja olímpico. Por que xadrez é esporte? Desenvolve concentração, raciocínio estratégico, memória, controle emocional sob pressão. Magnus Carlsen (Noruega): maior jogador de todos os tempos, campeão mundial de 2013 a 2023. Brasil: Fide Mestre Alexandr Fier e outros representantes. Esportes eletrônicos (e-sports): League of Legends, CS:GO, Free Fire têm torneios com prêmios milionários; Brasil é 2º maior mercado de e-sports do mundo; debate: e-sports são esporte? Dama, go, dominó, poker: outros jogos de estratégia com competições profissionais. A saúde do jogador de e-sports: esclarecer posturas, pausas, exercícios preventivos para quem joga muito tempo.', ['Quais habilidades cognitivas e emocionais o xadrez desenvolve que são transferíveis para o esporte convencional?', 'Os e-sports devem ser considerados esporte? Argumente usando os critérios de definição de esporte (competição, habilidade, esforço, regras).']),
  createLesson('g2-ef-b2-l15', 'L15: Dança Contemporânea e Expressão Corporal', 'educacao_fisica', 'A dança contemporânea rompeu com os padrões rígidos do ballet clássico e abriu espaço para corpos, histórias e formas de movimento diversas. História: Isadora Duncan (início do séc. XX) libertou a dança das sapatilhas de ponta; Martha Graham criou a técnica de contração e release; Pina Bausch criou o Tanztheater (teatro-dança). No Brasil: Lia Rodrigues (influência afrobrasileira), Déborah Colker (escalada como dança). Street dance como expressão contemporânea: breaking, krump, waacking, vogue. Breaking (breakdance): olímpico em Paris 2024 (Rayssa Leal e Phil Wizard); movimentos: toprock, footwork, freeze, power moves. O corpo como linguagem: como o corpo conta histórias sem palavras. Prática: sequência de expressão corporal com tema social.', ['Como a dança contemporânea difere do ballet clássico em termos de filosofia artística e tipos de corpo valorizados?', 'O que é o Tanztheater de Pina Bausch e por que ele é considerado revolucionário para a dança mundial?']),
  createLesson('g2-ef-b2-l16', 'L16: Aptidão Física — Reavaliação de Meio de Ano', 'educacao_fisica', 'Reavaliação das capacidades físicas no meio do ano — comparação com os dados do início do 1º bimestre. Baterias de testes: teste de Cooper ou teste de 6 minutos (resistência aeróbia); flexão de braço em 1 minuto (força-resistência de membros superiores); abdominal em 1 minuto (resistência de core); sentar-e-alcançar (flexibilidade); sprint de 20 metros (velocidade); salto horizontal parado (força explosiva). Análise individual: identificar progresso, estagnação ou declínio em cada capacidade. Discussão: por que a aptidão física pode mudar (positiva ou negativamente) em 6 meses? Quais fatores externos influenciam (estresse escolar, sono, alimentação, prática esportiva extracurricular)?', ['Após a reavaliação, em qual capacidade física você mais progrediu? E em qual ainda precisa melhorar? O que explica esses resultados?', 'Quais hábitos de vida (sono, alimentação, estresse, prática esportiva) você acredita que mais impactaram sua aptidão física neste semestre?']),
  createLesson('g2-ef-b2-l17', 'L17: Violência no Esporte — Torcidas e Fair Play', 'educacao_fisica', 'A violência no esporte é fenômeno preocupante. No futebol brasileiro: torcidas organizadas (hooligans brasileiros), brigas entre torcedores com mortes; racismo nos estádios (macaquinhos, bananas jogadas); homofobia nos gritos das arquibancadas. A FIFA e a CBF têm programas de combate: "Say No to Racism", regulamentos contra discriminação. Fair Play: a ideia de jogo limpo vai além das regras — é uma atitude de respeito ao adversário, ao árbitro e ao próprio esporte. Exemplos de fair play: Sportsmanship de atletas que ajudam adversários caídos; a decisão de Vanderlei Cordeiro de Melo após invasão do estádio em Atenas 2004 (perdeu o ouro por segundos após invasão). Educação para o fair play: como ensinar essa atitude desde cedo.', ['Quais são as formas mais comuns de violência nos estádios brasileiros e quais medidas têm sido tomadas para combatê-las?', 'Dê um exemplo de fair play no esporte que te marcou. Por que esse gesto é raro e ao mesmo tempo tão admirado?']),
  createLesson('g2-ef-b2-l18', 'L18: Revisão do 2º Bimestre e Projeto', 'educacao_fisica', 'Revisão e consolidação dos temas do 2º bimestre: esporte e política, capoeira avançada, ginástica rítmica, prevenção de lesões, yoga, esporte e mídia, princípios do treinamento, jogos indígenas, xadrez/e-sports, dança contemporânea. Projeto de 2º bimestre: em grupos de 3-4, produzir um "Guia de Prática Esportiva Segura" para adolescentes do Tocantins — escolhendo uma modalidade específica praticada na região, abordando: equipamentos, técnica básica, segurança, onde praticar em Palmas, benefícios para a saúde. Apresentação oral com demonstração prática. Avaliação por rubrica (conteúdo, apresentação, domínio técnico, originalidade).', ['Qual foi o tema do 2º bimestre que mais impactou sua visão sobre a Educação Física? Por quê?', 'No projeto do grupo, qual foi sua principal contribuição? O que você aprendeu sobre a modalidade que escolheram?']),
];

export const efLessonsB3: Lesson[] = [
  createLesson('g2-ef-b3-l1', 'L1: Fisiologia do Exercício — Como o Corpo Responde ao Esforço', 'educacao_fisica', 'A fisiologia do exercício estuda as respostas e adaptações do organismo ao esforço físico. Respostas agudas (durante o exercício): aumento da frequência cardíaca (FC máxima ≈ 220 - idade), maior volume de ejeção cardíaco, vasodilatação nos músculos ativos, ativação do metabolismo energético (ATP-CP, glicolítico, oxidativo). Adaptações crônicas (com o treino regular): hipertrofia cardíaca e aumento do volume de ejeção (coração de atleta), aumento da densidade capilar muscular, maior capacidade de utilização de gordura como combustível, redução da FC de repouso (atletas de elite: 40-50 bpm vs. 60-80 bpm de pessoas sedentárias). VO2 máximo: principal indicador de aptidão cardiovascular — volume máximo de oxigênio consumido por minuto. Prática: medir FC em repouso e após exercício progressivo.', ['Qual é a diferença entre uma resposta aguda ao exercício e uma adaptação crônica? Dê exemplos de cada uma.', 'O que é o VO2 máximo e por que ele é considerado o principal indicador de aptidão cardiovascular?']),
  createLesson('g2-ef-b3-l2', 'L2: Esporte e Saúde — Doenças Crônicas Não Transmissíveis', 'educacao_fisica', 'As DCNTs (Doenças Crônicas Não Transmissíveis) são a principal causa de morte no mundo e no Brasil: hipertensão, diabetes tipo 2, obesidade, doenças cardiovasculares, câncer. A atividade física regular reduz significativamente o risco: 35% menos risco de doença cardiovascular, 30% menos risco de diabetes tipo 2, 20-30% menos risco de alguns cânceres (cólon, mama). No Tocantins: prevalência de hipertensão e diabetes é maior no interior e em populações indígenas. O sedentarismo como pandemia: OMS estima que 1,4 bilhão de adultos são insuficientemente ativos. Recomendações OMS: 150-300 min de atividade aeróbia moderada/semana + 2x/semana de atividades de força. Brasil: apenas 39% da população atinge esse mínimo.', ['Como a atividade física regular reduz o risco de cada uma das principais DCNTs? Explique os mecanismos fisiológicos.', 'Considerando as recomendações da OMS, você atinge o mínimo de atividade física recomendado por semana? O que você poderia fazer para melhorar?']),
  createLesson('g2-ef-b3-l3', 'L3: Musculação e Treinamento de Força — Mitos e Ciência', 'educacao_fisica', 'A musculação é um dos exercícios mais estudados da ciência esportiva. Mitos a desconstruir: "musculação atrasa o crescimento de adolescentes" (FALSO — treino adequado é seguro e benéfico), "mulheres que treinam força ficam masculinas" (FALSO — mulheres têm 10-15x menos testosterona que homens), "treinar em jejum queima mais gordura" (QUESTIONÁVEL — prejudica o desempenho e a recuperação). Ciência da hipertrofia: síntese proteica muscular (SPM) é estimulada pela tensão mecânica; "janela anabólica" — importância de proteína pós-treino; sono como fundamental (80% do GH liberado no sono profundo). Treino para adolescentes: menor carga, técnica perfeita, supervisão, ênfase em movimentos funcionais (não isolamento muscular excessivo). Exercícios funcionais: agachamento, terra, empurrar, puxar, carregar.', ['Quais são os principais mitos sobre musculação para adolescentes e mulheres? O que a ciência diz sobre cada um?', 'Por que a técnica correta é mais importante do que a quantidade de carga no treinamento de força para adolescentes?']),
  createLesson('g2-ef-b3-l4', 'L4: Esportes Coletivos — Futebol: Copa do Mundo e Identidade', 'educacao_fisica', 'A Copa do Mundo é o evento esportivo mais assistido do mundo (3,5 bilhões de telespectadores em 2022). A trajetória do Brasil nas Copas: 5 títulos (1958, 1962, 1970, 1994, 2002); o trauma de 1950 (Maracanazo) e 2014 (7x1 contra a Alemanha). O futebol e a identidade brasileira: Gilberto Freyre e o "futebol mulato"; Eduardo Galeano ("O Futebol ao Sol e à Sombra") — o futebol como arte dos pobres. O negacionismo da Copa: crítica às obras, gastos públicos bilionários vs. benefício social questionável. Futebol feminino: trajetória da Seleção Brasileira Feminina — Marta como símbolo, tratamento desigual historicamente. Copa 2026: Estados Unidos, Canadá e México — o que esperar do Brasil?', ['Como o trauma do Maracanazo (1950) e o 7x1 (2014) afetaram a identidade esportiva brasileira? Quais reações culturais esses eventos geraram?', 'Por que a Copa do Mundo é criticada por movimentos sociais apesar de ser o evento esportivo mais popular do mundo?']),
  createLesson('g2-ef-b3-l5', 'L5: Esportes Radicais e de Aventura — Risco Calculado', 'educacao_fisica', 'Os esportes radicais e de aventura atraem pelo desafio, pela adrenalina e pela conexão com a natureza. Categorias: esportes aéreos (asa delta, paragliding, paraquedismo, wingsuit — maior risco); esportes aquáticos radicais (surf de ondas grandes, caiaque de corredeiras grau 5); esportes de montanha (escalada livre, alpinismo, base jumping). No Brasil: surf em Itacaré e Fernando de Noronha, kitesurf no Delta do Parnaíba (Maranhão), sandboard em Jalapão-TO. Gestão de risco: como esportistas radicais calculam e minimizam o risco (treinamento progressivo, equipamentos adequados, condições meteorológicas, parceiros experientes). A linha entre coragem e imprudência: estudo de casos de acidentes evitáveis. O Cerrado e os esportes de aventura: conservação ambiental como condição para a prática.', ['Qual é a diferença entre um esporte de aventura praticado com responsabilidade e uma prática imprudente? Quais são os critérios para essa distinção?', 'Por que Jalapão é considerado um dos melhores destinos de esportes de aventura do Brasil? Descreva as atividades possíveis e os cuidados necessários.']),
  createLesson('g2-ef-b3-l6', 'L6: Corrida de Rua — Da Iniciação ao Semiarremesso', 'educacao_fisica', 'A corrida de rua é o esporte de maior crescimento no Brasil na última década. Em 2023, o Brasil realizou mais de 6.000 provas de rua. Tipos de provas: 5 km (iniciante), 10 km (popular), meia maratona (21,097 km), maratona (42,195 km), ultramaratona (50-100 km+). Técnica de corrida eficiente: postura (tronco levemente inclinado à frente), cadência (180 passos/min é o ideal), aterrissagem (evitar calcanhada, aterrissar no médio-pé), braços (cotovelo 90°, mãos relaxadas). Lesões mais comuns: síndrome da banda iliotibial, fascite plantar, tendinite de Aquiles, joelho do corredor. Programa de iniciação: do zero a 5 km em 8 semanas (run/walk intervals). Corrida e sustentabilidade: corridas no cerrado, nas trilhas do Jalapão, corrida nas ruas de Palmas.', ['Por que a corrida de rua se tornou tão popular no Brasil? Quais fatores sociais e culturais explicam esse fenômeno?', 'Descreva as principais características de uma técnica de corrida eficiente. Como cada elemento contribui para o desempenho e a prevenção de lesões?']),
  createLesson('g2-ef-b3-l7', 'L7: Ciclismo — Sport e Mobilidade Urbana', 'educacao_fisica', 'O ciclismo tem dois grandes papéis: esporte de competição e meio de transporte sustentável. Ciclismo esportivo: Tour de France (mais prestigioso, 21 etapas, 3.500 km), Giro d\'Itália, Vuelta a España. Modalidades: estrada, pista, mountain bike (MTB), BMX (olímpico desde 1996). Brasil: Henrique Avancini (MTB cross-country — top 10 mundial). Fisiologia do ciclismo: potência (watts), FTP (Functional Threshold Power), zonas de treino. Ciclismo urbano: as ciclovias como política de mobilidade (Bogotá tem 550 km; Palmas tem ciclovias ao longo da Orla). Benefícios: redução de emissões, saúde cardiovascular, menos congestionamento. Desafios: segurança (43 ciclistas mortos no Brasil por dia em 2022), infraestrutura inadequada, intermodalidade (bicicleta + transporte público). Bike sharing (aluguel de bicicleta pública): experiências em grandes cidades.', ['Como o ciclismo pode contribuir para a mobilidade urbana sustentável? Quais são os desafios para sua implementação eficaz em cidades como Palmas?', 'Explique o que é o FTP (Functional Threshold Power) e por que ele é a principal métrica para ciclistas de competição.']),
  createLesson('g2-ef-b3-l8', 'L8: Dança Folclórica Avançada — Tocantins e Brasil', 'educacao_fisica', 'Aprofundamento nas danças folclóricas do Tocantins e do Brasil. No Tocantins: Caprichosa — a festa mais tradicional de Palmas (julho), com quadrilha junina, dança da baleia, folk-pop tocantinense; dança do Boi do Muquém (Natividade); danças dos povos indígenas Krahô (pehi e outras) e Karajá (hetohokÿ — festa dos homens). Danças folclóricas brasileiras por região: frevo e maracatu (Nordeste), samba de crioula e bumba-meu-boi (Maranhão), carimbó (Pará), siriri e cururu (Mato Grosso), maculelê e samba-de-roda (Bahia). Classificação: danças de salão, roda, fila, procissão, iniciática (indígenas). Patrimônio imaterial: como preservar sem engessalhar? Debate: folclore estático vs. folclore vivo (que se adapta). Prática: passos básicos da quadrilha junina.', ['Como as danças do povo Krahô e Karajá refletem sua cosmovisão e organização social? Por que é importante estudá-las nas aulas de EF?', 'Qual é a diferença entre folclore "congelado" (preservado exatamente como era) e folclore "vivo" (que se transforma)? Qual abordagem é mais adequada para a preservação cultural?']),
  createLesson('g2-ef-b3-l9', 'L9: Biomecânica do Movimento Humano', 'educacao_fisica', 'A biomecânica aplica os princípios da física ao movimento humano. Conceitos básicos: força (F = m×a), torque (força rotacional — fundamental em arremessos e golpes), alavanca (sistema osso-músculo como alavanca), centro de massa (estabilidade). Análise do movimento: planos de movimento (sagital, frontal, transverso); tipos de contração muscular (isométrica, concêntrica, excêntrica — excêntrica é a mais lesiva e eficaz para hipertrofia). Aplicações práticas: por que dobrar os joelhos ao levantar peso protege a coluna? Como o comprimento do pé de nadadeira imita o pé de pato? Por que correr em declive é mais lesivo que em subida? Por que atletas mais altos têm vantagem no basquete mas desvantagem na ginástica? Uso de tecnologia: análise de movimento em vídeo (biomecânica por smartphone).', ['Como os princípios de alavanca se aplicam ao movimento humano? Dê um exemplo esportivo onde a biomecânica da alavanca é decisiva.', 'Por que a contração muscular excêntrica (músculo se alonga enquanto gera força) é mais eficaz para a hipertrofia mas também mais propensa a gerar dores musculares?']),
  createLesson('g2-ef-b3-l10', 'L10: Esporte na Escola — Iniciação Esportiva e Projetos Sociais', 'educacao_fisica', 'A iniciação esportiva na escola é a base da cultura esportiva de um país. No Brasil, o esporte de alto rendimento depende de "peneiras" em clubes, mas a maioria não tem acesso. Projetos sociais esportivos de referência: Escolinhas da CBF (futebol), Projeto Viver do Esporte (atletismo em periferias), Projeto Basquete sem Fronteiras (NBA); Instituto Reação (judô — Flávio Canto, no Rio); Amigos da Escola. No Tocantins: projetos do Governo do Estado em parceria com confederações; o Sesi e o Sesc como promotores de esporte para todas as classes. Esporte como proteção social: o impacto de projetos esportivos na redução da vulnerabilidade juvenil — evidências de pesquisa. Debate: o esporte resolve problemas sociais ou apenas atenua os sintomas?', ['Por que os projetos sociais esportivos são importantes para a inclusão, mas não devem ser vistos como a única solução para a desigualdade social?', 'Cite um projeto social esportivo que você considera eficaz. Quais são os elementos que fazem esse projeto funcionar além do esporte em si?']),
  createLesson('g2-ef-b3-l11', 'L11: Voleibol de Praia — Técnica e Brasil', 'educacao_fisica', 'O vôlei de praia é uma das modalidades em que o Brasil é mais bem-sucedido na história olímpica. Contexto: modalidade olímpica desde Atlanta 1996; Brasil ganhou 6 ouros olímpicos (masculino: Emanuel/Ricardo; Alisson/Bruno; Sherif/Lucena em Paris 2024; feminino: Juliana/Larissa; Ágatha/Bárbara; Ana Patrícia/Duda em Paris 2024). Diferenças técnicas em relação ao vôlei de quadra: 2x2, sem libero, sets até 21 pts (3º set até 15), campo de areia, vento como fator tático, saque flutuante muito mais eficaz, defesa mais difícil (superfície instável). Fundamentos específicos: manchete "panqueca" na areia, cortada de praia (roll shot, pipe, line, diagonal), bloqueio de cabeça. Por que o Brasil domina o vôlei de praia? Análise de fatores culturais, climáticos e de infraestrutura.', ['Por que o Brasil é tão dominante no vôlei de praia? Quais fatores explicam essa supremacia histórica?', 'Explique as principais diferenças técnicas entre o vôlei de quadra e o vôlei de praia. Como essas diferenças afetam a estratégia de jogo?']),
  createLesson('g2-ef-b3-l12', 'L12: Tênis e Esportes Individuais — Mentalidade e Pressão', 'educacao_fisica', 'Os esportes individuais exigem uma relação com a pressão completamente diferente dos coletivos — você está sozinho na quadra, na pista ou no tatame. Tênis: psicologia do break point, do match point, da virada de set; Djokovic como mestre do controle emocional (mindset olímpico). Natação: Michael Phelps e sua rotina pré-prova (música, isolamento, visualização). Atletismo: Usain Bolt e a performance sob pressão — contraste entre descontração e explosão. Técnicas de psicologia esportiva: visualização (imaginar a performance antes de realizá-la ativa os mesmos circuitos neurais); breathing control (respiração pré-performance); rotinas de ativação; self-talk positivo ("Eu consigo", "Estou preparado"). Síndrome da impostora em atletas mulheres. Aplicação na vida: como essas técnicas funcionam em provas escolares?', ['Como atletas de elite lidam com a pressão de momentos decisivos? Quais técnicas de psicologia esportiva eles usam?', 'Como as técnicas de psicologia esportiva (visualização, controle respiratório, self-talk) podem ser aplicadas em situações de pressão escolar, como provas e apresentações?']),
  createLesson('g2-ef-b3-l13', 'L13: Ginástica Geral e Atividade Circense', 'educacao_fisica', 'A ginástica geral é a mais democrática das ginásticas — sem competição de alto rendimento, focada em expressão, cooperação e inclusão. Festival de ginástica geral: grupos de qualquer idade apresentam coreografias com combinação de aparelhos, dança, acrobacia e teatro. A atividade circense como prática corporal: malabarismo, acrobacia em grupo, tecido aéreo, perna de pau, equilibrismo. Benefícios: coordenação motora, confiança, cooperação, expressão artística. Elementos acrobáticos básicos em grupo: pirâmides humanas (base, intermediário, volante), bandeira (desequilíbrio controlado), portor (suporte de outro corpo). Segurança: colchões adequados, supervisão, progressão gradual. Circo social no Brasil: projetos que usam o circo como forma de inclusão social em periferias.', ['Por que a ginástica geral é considerada mais inclusiva do que as ginásticas de alto rendimento?', 'Quais habilidades físicas e sociais a prática de atividades circenses desenvolve? Por que o circo social é uma ferramenta de inclusão eficaz?']),
  createLesson('g2-ef-b3-l14', 'L14: Esporte e Gênero — Avanços e Desafios', 'educacao_fisica', 'A desigualdade de gênero no esporte tem raízes históricas profundas. História: Pierre de Coubertin, criador das Olimpíadas modernas, era contra a participação feminina ("um espetáculo feio e incorreto"). Primeiro ouro feminino olímpico: Charlotte Cooper (tênis, 1900). Hoje: Paris 2024 foi o primeiro com paridade de gênero (50% atletas femininas). Desafios persistentes: cobertura midiática desigual (esporte feminino recebe ~4% do tempo de cobertura no Brasil), diferença salarial (no futebol, as diferenças são abissais), assédio sexual e moral no ambiente esportivo, pressão estética sobre atletas femininas, transfobia (debate sobre mulheres trans no esporte). Brasil: Marta como símbolo, mas tratamento desigual da CBF histórico. Proposta: o que cada um pode fazer para apoiar o esporte feminino?', ['Quais são as principais formas de desigualdade de gênero ainda existentes no esporte mundial? O que explica essa persistência?', 'Qual é o debate sobre mulheres trans no esporte de alto rendimento? Quais são os argumentos de cada lado?']),
  createLesson('g2-ef-b3-l15', 'L15: Futsal — Técnica e Táticas Avançadas', 'educacao_fisica', 'O futsal é o futebol de quadra e Brasil é o maior campeão mundial da história. Diferenças em relação ao futebol de campo: bola mais pesada e menor, quadra dura, 5 jogadores, goleiro voa, reposição lateral com a mão, pivô como posição específica. Sistemas táticos avançados: 2-2 (quadrado), 3-1 (diamante com fixo), pressing alto. A função do fixo: o "lateral" do futsal, que inicia as jogadas. A função do pivô: referência na frente, gira para finalizar. Goleiro jogador: o goleiro do futsal tem muito mais participação técnica que no futebol. Famosos brasileiros: Falcão (considerado o maior de todos os tempos), Ricardinho, Ferrão. Prática: aplicação do sistema 2-2 com ênfase no papel de cada posição.', ['Quais são as principais diferenças táticas entre o futsal e o futebol de campo? Como o espaço menor muda a dinâmica do jogo?', 'Explique a função do "fixo" no futsal. Por que essa posição é fundamental para a construção do jogo?']),
  createLesson('g2-ef-b3-l16', 'L16: Programa Personal de Atividade Física', 'educacao_fisica', 'Desenvolver autonomia para planejar e executar uma rotina de atividade física é um dos maiores objetivos da EF escolar. Projeto individual: cada aluno cria seu "Programa Personal de AF" para os próximos 3 meses. Estrutura do programa: (1) Objetivo principal (saúde, performance, prazer, emagrecimento, etc.); (2) Modalidades escolhidas e por quê; (3) Frequência semanal (dias e horários); (4) Progressão de carga (como vai aumentar a dificuldade ao longo do tempo); (5) Monitoramento (como vai acompanhar seu progresso); (6) Plano de contingência (e se chover? e se o prazo mudar?). Reflexão: a atividade física precisa ser agradável para ser sustentável — o que realmente te motiva? Prazer intrínseco vs. meta extrínseca.', ['Qual é a diferença entre motivação intrínseca (prazer pela atividade) e extrínseca (meta externa) no contexto da atividade física? Qual é mais sustentável?', 'Apresente seu Programa Personal de AF: objetivo, modalidades, frequência, progressão e como vai monitorar seu progresso.']),
  createLesson('g2-ef-b3-l17', 'L17: Esporte e Ambiente — Sustentabilidade nas Práticas Corporais', 'educacao_fisica', 'O esporte depende do ambiente natural e ao mesmo tempo pode prejudicá-lo. Impactos negativos: trilhas com erosão por excesso de pisoteio, resíduos em rios e praias após eventos esportivos, uso de motores em esportes náuticos, pistas de esqui afetadas pelo degelo, construção de campos e arenas desflorestando áreas. Esporte sustentável: princípios de Leave No Trace, carbono zero em eventos (Jogos Olímpicos Paris 2024 como objetivo), equipamentos biodegradáveis, corridas de trail com regras de preservação. No Tocantins: a pesca esportiva no Araguaia e o impacto da pesca predatória; o sandboard nas dunas do Jalapão — como praticar sem degradar. Como cada esportista pode agir: carregar seu lixo, trilhas certificadas, respeitar a fauna e flora, não invadir áreas de proteção.', ['Quais são os principais impactos negativos que o esporte pode ter sobre o meio ambiente? Como esses impactos podem ser mitigados?', 'Por que o Jalapão representa tanto um polo de turismo de aventura quanto uma área ambientalmente sensível? Como equilibrar essas duas dimensões?']),
  createLesson('g2-ef-b3-l18', 'L18: Revisão do 3º Bimestre e Avaliação', 'educacao_fisica', 'Revisão e consolidação dos temas do 3º bimestre: fisiologia do exercício, musculação (mitos e ciência), Copa do Mundo e identidade, esportes radicais, corrida de rua, ciclismo, dança folclórica, biomecânica, esporte na escola, vôlei de praia, psicologia esportiva, ginástica geral, gênero no esporte, futsal, programa personal, esporte e ambiente. Avaliação prática: apresentação do Programa Personal de AF + execução de uma atividade técnica à escolha. Avaliação teórica: análise crítica de um tema do bimestre (redação de 20 linhas). Reflexão: você mudou algum hábito físico ou de lazer ao longo deste ano? O que a EF significou para você para além das aulas?', ['Dos temas estudados neste bimestre, qual mais mudou sua visão sobre o esporte e a atividade física? Por quê?', 'Como a disciplina de Educação Física contribuiu para além das capacidades físicas — no conhecimento, na consciência crítica, na identidade?']),
];

export const efLessonsB4: Lesson[] = [
  createLesson('g2-ef-b4-l1', 'L1: Esporte de Alto Rendimento vs. Esporte para Todos', 'educacao_fisica', 'Existe uma tensão fundamental no esporte moderno: o modelo de alto rendimento (busca de recordes, medalhas, contratos milionários) vs. o esporte participativo (saúde, lazer, socialização, inclusão). Política esportiva brasileira: Lei Pelé (Lei 9.615/1998), Lei de Incentivo ao Esporte (Lei 11.438/2006), Política Nacional de Esporte. Orçamento: historicamente, o alto rendimento absorve a maior parte dos recursos, enquanto o esporte de base e a EF escolar são subfinanciados. O Sistema Nacional de Esporte propõe integrar os dois modelos. Debate: qual deve ser a prioridade do Estado? Alto rendimento que gera orgulho nacional e traz recursos ou esporte de base que promove saúde pública?', ['Qual deve ser a prioridade do Estado no investimento esportivo: alto rendimento ou esporte para todos? Justifique sua resposta com argumentos.', 'Como a falta de investimento no esporte escolar (EF e esporte extracurricular) afeta o desenvolvimento do alto rendimento esportivo no longo prazo?']),
  createLesson('g2-ef-b4-l2', 'L2: Doping — Ciência, Ética e História', 'educacao_fisica', 'O doping é o uso de substâncias ou métodos proibidos para melhorar artificialmente o desempenho. História: Ben Johnson (1988, Seul), Lance Armstrong (ciclismo — caso mais famoso, 7 títulos do Tour de France anulados), Caso da Rússia (Rio 2016 e Tóquio 2020 — programa estatal de doping). Substâncias: EPO (eritropoietina — aumenta glóbulos vermelhos), esteroides anabolizantes (aumentam massa muscular), hormônio do crescimento, transfusão de sangue. WADA (Agência Mundial Antidoping) e ABCD (Autoridade Brasileira de Controle do Doping): testes in-competition e out-of-competition. Doping no esporte amador e nas academias: uso de anabolizantes entre jovens — riscos à saúde (acne severa, ginecomastia em homens, virilização em mulheres, danos hepáticos, infarto, AVC). Reflexão: o que o doping revela sobre os valores do esporte moderno?', ['Quais são os principais riscos para a saúde do uso de anabolizantes entre adolescentes? Por que o risco é maior nessa faixa etária?', 'O caso da Rússia revelou que havia um programa estatal de doping. O que isso nos diz sobre a relação entre esporte e política?']),
  createLesson('g2-ef-b4-l3', 'L3: Futuro do Esporte — Tecnologia, VAR e Wearables', 'educacao_fisica', 'A tecnologia está transformando o esporte. VAR (Video Assistant Referee): sistema de revisão de vídeo no futebol — elimina erros grotescos, mas cria polêmica (tempo de decisão, interpretação). Goal-line technology (bola cruzou a linha?). Wearables em esportes: GPS para distância e velocidade, monitor cardíaco, lactato sanguíneo, acelerômetro para impacto. Analytics no esporte: Moneyball (Oakland A\'s — beisebol), analytics no basquete (shot chart, PIPM, RAPTOR). Inteligência artificial no esporte: previsão de lesões por machine learning, análise tática automatizada (Wyscout, InStat), árbitros de IA no tênis e no badminton. Robótica esportiva: robôs que batem cestas de basquete, robôs goleiros. Questão: a tecnologia torna o esporte mais justo ou menos humano? Onde está o limite?', ['O VAR tornou o futebol mais justo? Quais são os argumentos a favor e contra essa tecnologia?', 'Como a análise de dados (analytics) mudou a forma como times e treinadores tomam decisões estratégicas no esporte contemporâneo?']),
  createLesson('g2-ef-b4-l4', 'L4: Esporte e Raça — Representatividade e Racismo', 'educacao_fisica', 'A relação entre raça e esporte no Brasil é complexa e reveladora. Dados: 70% dos jogadores de futebol profissional no Brasil são negros ou pardos, mas apenas 5% dos dirigentes de clubes são negros. Racismo no esporte: cânticos racistas nos estádios, comentários racistas nas redes sociais (Aranha/Santos, Vinícius Jr. no Real Madrid). Código de etiqueta do racismo esportivo: o "é coisa de torcedor, não de clube" como argumento de isenção. Representatividade: Marta, Pelé, Ronaldo, Marta como ícones que inspiram gerações de jovens negros. A superrepresentação de negros em alguns esportes e sub-representação em outros (golfe, tênis, natação no Brasil — elitismo estrutural). Programas de combate ao racismo: "Eu Tenho Orgulho" (FIFA), Show Racismo Red Card.', ['Por que há super-representação de negros em alguns esportes e sub-representação em outros no Brasil? O que isso revela sobre a estrutura da sociedade?', 'Quais são as consequências do racismo sofrido por atletas como Vinícius Jr.? Como o movimento antirracista no esporte pode ser fortalecido?']),
  createLesson('g2-ef-b4-l5', 'L5: Preparação Física para o ENEM e Vestibular', 'educacao_fisica', 'O período de preparação intensa para o ENEM e vestibulares aumenta o sedentarismo e o estresse dos estudantes. Pesquisas mostram: estudantes que praticam atividade física regular durante a preparação para provas têm desempenho até 15% superior em testes cognitivos. Protocolo de AF durante a preparação: 30 min/dia de exercício aeróbio moderado melhora memória, concentração e humor; 10 min de exercício intenso antes de estudar aumenta o BDNF (fator de crescimento neural); pausas ativas de 5 min a cada 50 min de estudo reduzem a fadiga mental. Exercícios sem equipamento para fazer em casa: circuito funcional (agachamento, flexão, abdominal, polichinelo). Sono como prioridade: 8h de sono consolidam a memória estudada. Gerenciar a ansiedade: técnicas de respiração (4-7-8), meditação de 10 min.', ['Como a atividade física regular pode melhorar o desempenho nos estudos do ponto de vista neurocientífico?', 'Crie um protocolo de AF semanal para um estudante que estuda 8h/dia na reta final do ENEM: como encaixar movimento na rotina intensa?']),
  createLesson('g2-ef-b4-l6', 'L6: Corrida de Orientação e Esportes ao Ar Livre', 'educacao_fisica', 'A corrida de orientação combina atletismo e leitura de mapas — você usa bússola e mapa topográfico para encontrar checkpoints em um terreno desconhecido. Surgiu na Escandinávia no início do século XX; modalidade olímpica de candidatura. Benefícios: raciocínio espacial, tomada de decisão em movimento, resistência física, conexão com a natureza. No Tocantins: o Cerrado oferece terreno ideal para corrida de orientação. Relacionados: bushcraft (habilidades de sobrevivência), geocaching (caça ao tesouro digital em coordenadas GPS). Esportes ao ar livre como contraponto ao mundo digital: pesquisas de "banho de floresta" (shinrin-yoku) do Japão mostram que 2h/semana na natureza reduz cortisol em 30%. A natureza como remédio — perspectiva contemporânea de saúde.', ['O que é a corrida de orientação e quais habilidades ela desenvolve além da aptidão física?', 'O que a pesquisa japonesa sobre "banho de floresta" (shinrin-yoku) revelou sobre os benefícios do contato com a natureza para a saúde? Como isso se relaciona com práticas corporais ao ar livre?']),
  createLesson('g2-ef-b4-l7', 'L7: Atividade Física ao Longo da Vida', 'educacao_fisica', 'A atividade física não é só para jovens — é para toda a vida. Pirâmide da vida ativa: infância (movimento espontâneo, brincadeiras livres), adolescência (esportes coletivos, habilidades específicas), adultos jovens (manutenção, esportes preferidos), adultos maduros (saúde, prevenção de doenças crônicas), idosos (manutenção da funcionalidade). Exercício na gestação: seguro e recomendado (natação, caminhada, pilates — evitar contato e quedas). Exercício para idosos: treinamento de equilíbrio e força muscular são os mais importantes para prevenir quedas (principal causa de morte em idosos). A "crise de movimento" nas cidades: como a urbanização e o trabalho sedentário criaram ambientes antiatividade. Design de cidades ativas: ciclovias, calçadas acessíveis, praças com academia, parques urbanos. Palmas: Parque Cesamar, orla do lago e as academias ao ar livre.', ['Por que o treinamento de equilíbrio e força muscular é considerado o mais importante para idosos? Quais são os riscos que essa prática previne?', 'Como o design urbano de Palmas (parques, orla, ciclovias) pode facilitar ou dificultar a prática de atividade física? O que poderia ser melhorado?']),
  createLesson('g2-ef-b4-l8', 'L8: Criatividade Corporal — Criando Novas Práticas', 'educacao_fisica', 'A criatividade no movimento é uma habilidade humana fundamental. Projeto de criação: em grupos de 4, criar uma prática corporal nova combinando elementos de pelo menos 2 modalidades estudadas ao longo do ano. Requisitos: (1) Nome e regras da prática; (2) Objetivo (saúde, lazer, competição?); (3) Número de participantes; (4) Equipamentos necessários; (5) Valores educacionais promovidos; (6) Demonstração prática para a turma. Exemplos de práticas criativas já existentes: Bossaball (combinação de voleibol + capoeira + música + trampolim, criado na Bélgica por um brasileiro); Quidditch (Harry Potter adaptado para o campo — agora chamado Quadball). Reflexão: o movimento humano é infindável em suas possibilidades criativas.', ['Qual foi a prática corporal criada pelo seu grupo? Descreva as regras, o objetivo e os valores que ela promove.', 'O que o processo de criação de uma nova prática corporal ensinou sobre os elementos fundamentais de qualquer esporte ou jogo?']),
  createLesson('g2-ef-b4-l9', 'L9: Avaliação Final de Aptidão Física', 'educacao_fisica', 'Avaliação física final do ano — a terceira do ciclo (1ª no início do 1º bimestre, 2ª no meio do 2º bimestre, 3ª agora). Bateria completa de testes: teste de Cooper ou 6 minutos (resistência aeróbia); flexão de braço 1 min (força-resistência membros superiores); abdominal 1 min (resistência de core); sentar-e-alcançar (flexibilidade); sprint 20m (velocidade); salto horizontal parado (força explosiva). Análise longitudinal: comparar as 3 medições. Quem progrediu mais? Quem teve melhora mais consistente ao longo do ano? O que explica diferenças individuais? Reflexão: os testes de aptidão física medem apenas uma dimensão da saúde — e a dimensão emocional, social e intelectual?', ['Comparando as 3 avaliações físicas do ano, em qual capacidade você mais progrediu? O que explica esse progresso?', 'Os testes de aptidão física capturam toda a dimensão da saúde de uma pessoa? O que eles deixam de medir?']),
  createLesson('g2-ef-b4-l10', 'L10: Projeto Final — Festival de Práticas Corporais', 'educacao_fisica', 'Projeto final do ano: Festival de Práticas Corporais da 2ª Série. Cada grupo (3-4 alunos) escolhe uma prática corporal (esporte, dança, luta, ginástica, esporte indígena, prática criativa) e organiza uma estação para o festival. Requisitos de cada estação: (1) Banner explicativo com história, regras e benefícios; (2) Demostração da prática (5 min); (3) Participação dos visitantes (todos da escola podem participar); (4) Conexão com saúde e/ou cultura regional. O festival é aberto para outras turmas e serve como celebração do aprendizado do ano. Avaliação: rúbrica contemplando domínio técnico, capacidade de ensinar, comunicação e criatividade.', ['O que você aprendeu ao ensinar uma prática corporal para outras pessoas? Por que ensinar é uma das formas mais profundas de aprender?', 'Avalie o Festival de Práticas Corporais: o que funcionou bem? O que poderia ser melhorado numa próxima edição?']),
  createLesson('g2-ef-b4-l11', 'L11: Corpo, Beleza e Sociedade — Padrões e Resistência', 'educacao_fisica', 'A indústria da beleza vale trilhões e usa o corpo esportivo como ideal inatingível. Padrões de beleza históricos: corpo varia com o tempo e a cultura (renascimento glorificava corpos plenos, hoje a magreza é o ideal). A indústria da aparência: academia como lugar de escultura do corpo, não de saúde; filtros do Instagram e dismorfia corporal; dietas restritivas e transtornos alimentares (anorexia, bulimia afetam 5 milhões de brasileiros). Movimentos de resistência: body positivity, fat acceptance, representatividade de corpos diversos na mídia, atletas de alto rendimento com corpos "não-padrão". Allyson Felix, Serena Williams — como atletas negras são julgadas duplamente por performance e aparência. Reflexão: seu corpo é seu — e ele é capaz de coisas extraordinárias independentemente de estar dentro do "padrão".', ['Como a indústria da beleza e as redes sociais criam padrões corporais inatingíveis? Quais são os impactos psicológicos na saúde mental dos jovens?', 'O que são os movimentos de body positivity e body neutrality? Qual deles você considera mais saudável como filosofia de relação com o próprio corpo?']),
  createLesson('g2-ef-b4-l12', 'L12: Esportes Paralímpicos — Tecnologia e Inclusão', 'educacao_fisica', 'As próteses e tecnologias assistivas transformaram o paradesporto. Próteses de corrida (lâminas de carbono): Oscar Pistorius foi o primeiro duplo amputado a correr nas Olimpíadas (Londres 2012) — debate sobre vantagem tecnológica. Cadeiras de rodas de basquete e tênis: ergonomia e engenharia específicas. Handbike e ciclismo para cadeirantes. Goalball: esporte para cegos ou com visão reduzida — jogo de equipe com bola com guizos, todos vendados. Bocce paralímpico: esporte de precisão que pode ser jogado por pessoas com qualquer tipo de deficiência motora. Brasil e paradesporto: 4ª maior delegação em Paris 2024, 22 medalhas. Desafio: como incluir o paradesporto nas aulas regulares de EF? Aula experimental: simular algum esporte paralímpico (goalball com venda, basquete em cadeira).', ['Por que as próteses de corrida geraram polêmica sobre vantagem tecnológica? Esse debate é justo? Qual é sua opinião?', 'Após a aula experimental de esporte paralímpico, o que você sentiu e o que aprendeu sobre o que significa ter uma deficiência no contexto esportivo?']),
  createLesson('g2-ef-b4-l13', 'L13: Educação Física — Um Olhar Para o Futuro', 'educacao_fisica', 'A EF escolar está em transformação. Tendências futuras: (1) Integração de tecnologia (apps de monitoramento, exergames, realidade aumentada); (2) Personalização (programas adaptados ao perfil individual por dados biométricos); (3) Natureza e ao ar livre (reação à vida digital); (4) Práticas meditativas e integrativas (yoga, tai chi — já reconhecidas pela OMS); (5) Esporte de rendimento + saúde integrados. O que não deve mudar: o movimento humano como direito, a brincadeira livre como necessidade, o corpo como forma de conhecer o mundo, o esporte como espaço de solidariedade e superação. Você como agente: como vai usar o que aprendeu de EF para construir uma vida ativa, saudável e com sentido?', ['Como você imagina as aulas de Educação Física daqui a 20 anos? Quais tendências você considera mais promissoras?', 'Das práticas corporais que você conheceu ao longo da 2ª Série, quais pretende manter na sua vida adulta? Por quê?']),
  createLesson('g2-ef-b4-l14', 'L14: Comunidade Ativa — EF fora da Escola', 'educacao_fisica', 'A Educação Física escolar deve ser o ponto de partida, não o único espaço de movimento. Recursos da comunidade em Palmas: Parque Cesamar (caminhadas, corridas, ciclismo), Orla do Lago (academia ao ar livre, quadras), piscinas do SESI e SESC, quadras poliesportivas de bairro, estúdios de dança, academias de judô e capoeira. Eventos esportivos em Palmas: Maratona Orla, Triathlon do Lago, competições escolares da SEDUC. Como se engajar: aplicativos para encontrar grupos de corrida, aulas coletivas gratuitas, projetos de voluntariado esportivo. Criando hábitos duradouros: a pesquisa mostra que é preciso ~66 dias (não 21) para instalar um hábito consistente. A estratégia dos "hábitos-âncora": associar atividade física a algo que você já faz (sempre depois do almoço, sempre pela manhã ao acordar).', ['Quais recursos para prática de atividade física existem na sua comunidade (bairro, Palmas) que você não sabia ou não aproveitava?', 'Como você planeja manter um estilo de vida ativo após sair da escola? Quais barreiras você prevê e como pretende superá-las?']),
  createLesson('g2-ef-b4-l15', 'L15: Avaliação Integrada — Teoria e Prática', 'educacao_fisica', 'Avaliação integrada final do ano: cada aluno apresenta um portfólio físico-reflexivo. Componentes do portfólio: (1) Registro das 3 avaliações físicas do ano com análise de progresso; (2) Reflexão sobre 3 práticas corporais que mais o marcaram e por quê; (3) Programa Personal de AF (criado no 3º bimestre) — o que foi aplicado? O que funcionou?; (4) Uma análise crítica de 1 tema teórico (esporte e raça, gênero, saúde mental, cultura etc.) com suas reflexões pessoais; (5) Metas de vida ativa para os próximos 5 anos. Avaliação da rubrica: não apenas pela qualidade física, mas pela profundidade reflexiva e pelo engajamento ao longo do ano.', ['Olhando para o portfólio de todo o ano, qual foi a maior mudança de perspectiva que a EF trouxe para você?', 'Quais são suas metas de vida ativa para os próximos 5 anos? Como a EF escolar te preparou para alcançá-las?']),
  createLesson('g2-ef-b4-l16', 'L16: Memória do Corpo — Experiências que Ficam', 'educacao_fisica', 'O corpo tem memória — não apenas o cérebro. A "memória muscular" é um fenômeno real: habilidades motoras aprendidas (andar de bicicleta, nadar, chutar uma bola) são armazenadas em circuitos subcorticais (cerebelo, gânglios basais) e permanecem por décadas sem prática. O aprendizado motor é diferente do aprendizado cognitivo: exige repetição, feedback proprioceptivo, tentativa e erro. Memórias corporais afetivas: o cheiro da grama depois da chuva, o som da bola no cesto, o peso do colega no ombro numa pirâmide. Essas memórias compõem quem somos. Atividade final: cada aluno escreve uma "carta para o seu corpo" — reconhecendo o que ele fez por você ao longo do ano, o que você lhe pediu, o que ele te deu.', ['O que você entende por "memória muscular"? Como esse fenômeno explica por que certas habilidades motoras nunca são esquecidas?', 'Escreva sua "carta para o seu corpo": reconheça as conquistas físicas deste ano, as dificuldades enfrentadas e o que você quer para esse corpo no futuro.']),
  createLesson('g2-ef-b4-l17', 'L17: Celebração — Encerramento da 2ª Série', 'educacao_fisica', 'A última aula de EF da 2ª Série é um momento de celebração e gratidão. Atividade: "Olimpíadas da 2ª Série" — minitorneio amistoso com modalidades escolhidas pela turma. Regras especiais: todos devem participar em pelo menos uma modalidade; foco na alegria e na inclusão, não na competição acirrada. Após as atividades: roda de fechamento. Cada aluno completa: "No próximo ano de EF, quero...". Mensagem do professor: a 3ª Série é o último ano. Use-o para consolidar hábitos que vão muito além do ENEM — hábitos de movimento, de cuidado com o corpo e com a saúde mental. Parabéns pela jornada.', ['O que a Educação Física significou para você neste ano? O que você carrega desta experiência para a 3ª Série e para a vida?', 'Complete: "A prática corporal que descobri este ano e quero continuar praticando é... porque...". Justifique sua escolha.']),
  createLesson('g2-ef-b4-l18', 'L18: Planejamento para a 3ª Série', 'educacao_fisica', 'Olhando para a frente: a 3ª Série de EF vai consolidar e aprofundar tudo que foi construído. Prévia do que vem: análise crítica do esporte como fenômeno global, práticas corporais avançadas, projeto comunitário de atividade física, preparação para a vida ativa adulta. Preparação para o ENEM em EF: embora EF não seja cobrada diretamente, as disciplinas da área de Linguagens e Códigos incluem questões sobre corpo, saúde, esporte e cultura. Como se preparar: continuar praticando, ler sobre temas de saúde e esporte, acompanhar os Jogos Olímpicos como fenômeno cultural e geopolítico. Meta pessoal de férias: estabelecer uma prática de atividade física para o recesso escolar — começar o ano já em movimento.', ['Quais expectativas você tem para a EF na 3ª Série? O que gostaria de aprofundar ou explorar?', 'Estabeleça uma meta de atividade física para as férias: o que você vai fazer, com que frequência e com quem?']),
];
